#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define KM_SLEEP 0
#define KSTAT_NAMED_STR_PTR(k) ((k)->value)
#define kstat_named_setstr(k, str) ((k)->value = (str))

typedef struct {
    char *value;
} kstat_named_t;

void *kmem_alloc(size_t size, int flags) {
    return malloc(size);
}

size_t strlcpy(char *dst, const char *src, size_t size) {
    size_t len = strlen(src);
    if (size > 0) {
        size_t copy_size = (len >= size) ? size - 1 : len;
        memcpy(dst, src, copy_size);
        dst[copy_size] = '\0';
    }
    return len;
}

static void set_string(kstat_named_t *k, const char *str, size_t len, const char *alt) {
    char *tmp;
    if (KSTAT_NAMED_STR_PTR(k) == NULL) {
        if (len > 0) {
            tmp = kmem_alloc(len + 1, KM_SLEEP);
            (void)strlcpy(tmp, str, len);
        } else {
            tmp = alt;
        }
        kstat_named_setstr(k, tmp);
    }
}

int main() {
    kstat_named_t kstat = {NULL};
    char *str = "";
    size_t len = strlen(str);
    char *alt = "";

    set_string(&kstat, str, len, alt);

