#include <stdio.h>
#include <string.h>

// Function to read a long integer from a byte array
unsigned long read_long(const unsigned char *buf) {
    return ((unsigned long)buf[3]) << 24 |
           ((unsigned long)buf[2]) << 16 |
           ((unsigned long)buf[1]) << 8 |
           (unsigned long)buf[0];
}

// Function to check if the buffer contains a valid long integer at the specified offset
int func(const unsigned char *buf, size_t bufsize) {
    // Check if the first byte is 0x80
    if (buf[0] != 0x80) return 0;

    // Calculate the offset based on the long integer value
    unsigned long long long_value = read_long(buf);
    unsigned long offset = (long_value ^ 0x80000000) + 4;

    // Check if the buffer has enough space for the offset
    if (bufsize < offset) return 0;

    // Check if the next six bytes match the expected string "..."
    if (memcmp(buf + offset - 6, "", 6)) return 0;

    // Return the calculated offset
    return offset;
}

int main() {
    unsigned char buffer[100];
    size_t bufsize = sizeof(buffer);

    // Set the first byte to 0x80
    buffer[0] = 0x80;

    // Call the function with the buffer and its size
    int result = func(buffer, bufsize);

    // Print the result
    printf("%d\n", result);

    return 0;
}
