#include <stdio.h>
#include <stdlib.h>
#include <sys/stat.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#define EX_USAGE 64

static int check_directory_permissions(const char *progname, const char *mountpoint) {
    int err;
    struct stat statbuf;

    err = stat(mountpoint, &statbuf);
    if (err) {
        fprintf(stderr, "%s: %s\n", progname, strerror(errno));
        return EX_USAGE;
    }

    if (!S_ISDIR(statbuf.st_mode)) {
        fprintf(stderr, "%s: %s is not a directory\n", progname, mountpoint);
        return EX_USAGE;
    }

    if (!getuid() || geteuid())
        return 0;

    if (statbuf.st_uid != getuid()) {
        fprintf(stderr, "%s: %s does not belong to you\n", progname, mountpoint);
        return EX_USAGE;
    }

    if ((statbuf.st_mode & S_IRWXU) != S_IRWXU) {
        fprintf(stderr, "%s: %s has incorrect permissions\n", progname, mountpoint);
        return EX_USAGE;
    }

    return 0;
}

int main(int argc, char *argv[]) {
    if (argc != 2) {
        fprintf(stderr, "Usage: %s <mountpoint>\n", argv[0]);
        return EX_USAGE;
    }

    return check_directory_permissions(argv[0], argv[1]);
}
