    return flag == SECURE_KEEP_CAPS;
}

void clear_cap(unsigned int *cap) {
    *cap = 0;
}

static inline void update_caps(cred *new, const cred *old) {
    if ((old->uid == 0 || old->euid == 0 || old->suid == 0) &&
        (new->uid != 0 && new->euid != 0 && new->suid != 0) &&
        !is_secure(SECURE_KEEP_CAPS)) {
        clear_cap(&new->cap_permitted);
        clear_cap(&new->cap_effective);
    }

    if (old->euid == 0 && new->euid != 0)
        clear_cap(&new->cap_effective);

    if (old->euid != 0 && new->euid == 0)
