#define MAX_PROBE_SCORE 100
#define MIN_FRAME_CHECKS 4

static int check_frame(AVProbeData *p, int frame_index) {
    if (frame_index >= MIN_FRAME_CHECKS) {
        unsigned offset = AV_RL32(p->buf + 18 + frame_index * 16);
        if (offset < 22) {
            return 0;
        }
        if (offset + 8 > p->buf_size) {
            return 0;
        }
        if (p->buf[offset] != 40 && AV_RB64(p->buf + offset) != PNGSIG) {
            return 0;
        }
    }
