#include <stdio.h>
#include <string.h>
#include <ctype.h>

static int is_space(int c) {
    return isspace(c);
}

static char *trim_whitespace(char *str) {
    char *start = str;
    char *end = str + strlen(str) - 1;

    // Move start pointer to the first non-space character
    while (start <= end && is_space(*start)) {
        start++;
    }

    // Move end pointer to the last non-space character
    while (end >= start && is_space(*end)) {
        end--;
    }

    // If there's no whitespace, return the original string
    if (start > end) {
        return str;
    }

    // Remove trailing spaces
    end++;

    // Null-terminate the trimmed string
    *end = '\0';

    return str;
}

int main() {
    char str[] = "";
    char *trimmed_str = trim_whitespace(str);

    if (trimmed_str) {
        printf("%s", trimmed_str);
    } else {
        printf("");
    }

    return 0;
}
