 tsize_t (*putBuf)(struct gdIOCtx *ctx, tdata_t data, tsize_t size);
} gdIOCtx;
static tsize_t func(thandle_t clientdata, tdata_t data, tsize_t size)
{
 tiff_handle *th = (tiff_handle *)clientdata;
 gdIOCtx *ctx = th->ctx;
 size = (ctx->putBuf)(ctx, data, size);
 if(size + th->pos>th->size) {
 th->size = size + th->pos;
 th->pos += size;
 }
 return size;
}
tsize_t dummy_putBuf(gdIOCtx *ctx, tdata_t data, tsize_t size) {
 return size; 
}
