 tiff_handle th;
 gdIOCtx ctx;
 ctx.putBuf = dummy_putBuf;
 th.ctx = &ctx;
 th.pos = 0;
 th.size = 0;
 char data[100];
 tsize_t written = func(&th, data, sizeof(data));
 printf("", written);
 return 0;
}

